Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
src/build-country.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
let timezonesMap;

export default function buildCountry(data, id) {
  const name = data.countries[id];
  if (!name) return null;

  const tzMap = getTimezonesMap(data)[id] || {};

  return {
    id,
    name,
       timezones: tzMap.current || ["Stryker was here"],
<PLACEHOLDER>
    allTimezones: tzMap.all || [],
  };
}

function getTimezonesMap(data) {
  if (!timezonesMap) timezonesMap = buildTimezonesMap(data);
  return timezonesMap;
}

function buildTimezonesMap(data) {
  return Object.keys(data.timezones).reduce((result, id) => {
    const tz = data.timezones[id];
    const { c, a } = tz;
    const aliasTz = data.timezones[a] || {};
    const countries = c || aliasTz.c;

    if (!countries) return result;

    countries.forEach((country) => {
      if (!result[country]) Object.assign(result, { [country]: { current: [], all: [] } });
      if (tz.r === undefined) result[country].current.push(id);
      result[country].all.push(id);
    });

    return result;
  }, {});
}

In the original code, <PLACEHOLDER> has the value:

-       allTimezones: tzMap.all || [],
In the mutated code, <PLACEHOLDER> has the value:

+       allTimezones: tzMap.all || ["Stryker was here"],


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
